        std::string errorMsg = "ERROR: Texture from surface '" + filename + "' could not be created: " + SDL_GetError();
        SDL_LogError(SDL_LOG_CATEGORY_ERROR, errorMsg.c_str());

        throw std::runtime_error(errorMsg);
    }
